from ragas import evaluate, EvaluationDataset, SingleTurnSample
from ragas.metrics import Faithfulness, AnswerRelevancy
import json, pathlib

def build_dataset_from_logs(log_dir: str) -> EvaluationDataset:
    """Build a RAGAS dataset from JSONL production logs.

    Each log line is expected to be:
    {"question": ..., "context_chunks": [...], "answer": ...}
    Ground truth is not required for these two metrics.
    """
    samples = []
    for path in sorted(pathlib.Path(log_dir).glob("*.jsonl")):
        for line in path.read_text().splitlines():
            entry = json.loads(line)
            samples.append(SingleTurnSample(
                user_input=entry["question"],
                retrieved_contexts=entry["context_chunks"],
                response=entry["answer"],
                # reference intentionally omitted — not needed
            ))
    return EvaluationDataset(samples=samples)

def production_faithfulness_check(
    log_dir: str,
    judge_llm,
    faithfulness_threshold: float = 0.90,
) -> dict:
    """Score faithfulness on production logs. Returns summary dict."""
    dataset = build_dataset_from_logs(log_dir)
    if not dataset.samples:
        return {"status": "no_data", "n": 0}

    result = evaluate(
        dataset=dataset,
        metrics=[
            Faithfulness(llm=judge_llm),
            AnswerRelevancy(llm=judge_llm),
        ],
    )
    scores = dict(result)
    faith = scores.get("faithfulness", 0.0)
    return {
        "status": "pass" if faith >= faithfulness_threshold else "fail",
        "faithfulness": faith,
        "answer_relevancy": scores.get("answer_relevancy", 0.0),
        "n": len(dataset.samples),
        "threshold": faithfulness_threshold,
    }
